import{_ as t,o as r,c as n,j as e,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const b=JSON.parse('{"title":"古老骨片","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/3.B级/古老骨片.md","filePath":"4.资源分区/7.物品与装备/4.奇物/3.B级/古老骨片.md"}'),o={name:"4.资源分区/7.物品与装备/4.奇物/3.B级/古老骨片.md"};function d(l,a,_,i,c,h){return r(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"古老骨片",tabindex:"-1"},[p("古老骨片 "),e("a",{class:"header-anchor",href:"#古老骨片","aria-label":'Permalink to "古老骨片"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),s('<h1 id="古老骨片-1" tabindex="-1">古老骨片 <a class="header-anchor" href="#古老骨片-1" aria-label="Permalink to &quot;古老骨片&quot;">​</a></h1><p>古老骨片<br> 占据护符位</p><p>B+2000</p><p>指甲盖大小的一枚骨片，似乎是从某人的尸骸中剥落，漫长的岁月已经让他风干，却丝毫没有腐朽。</p><p>也许你认为是自己选择购买这枚骨片，实际上是这枚骨片选择了你，他才会到达你的手中，遗骸的主人决定注视你，只是你尚不知晓。</p><p>若你踌躇不前：当你陷入困惑，不知前路在何方，ST可以让一个头戴荆棘王冠，双手穿洞的身影浮现在你的身侧，向你低语一个大致的方向或者地点名词，那里也许就是你需要前往的方向，并且时间上的误差不会超过一周，这道身影只有你能看见，这份低语只有你能听到，在你看清这个身影之前这个身影就会消失。这是一个B级命运来源的预知效果。</p><p>若是心存迷惘：一场景一次，当一场战斗中有一名友方角色失去战斗能力，且你失去了所有完好或失去了一半结构值，在如此困境，一份低语便会萦绕在你的耳边：”若心存迷惘，便不要击发“，进行第一次吟唱。每当经过战斗轮次中任意一个单位的回合，这份低语就会再吟唱一次，合计吟唱三次。吟唱三次后你的第一个回合，这份低语会进行最后一次吟唱：”若心存迷惘，便不要击发，要有所成长……再次，那样的话，通往新道路的大门将会打开“，你的下一次攻击伤害增加一倍，若对方具有反震、折射、反伤、打断性反击等会让你因此次攻击受伤的能力，则在此次攻击时你的眼中将隐隐浮现黑色的火焰，此次攻击额外获得1附加成功。</p><p>即便身躯死亡：即便身躯死亡，也能获得永生。那道身影如此低语，在你死亡时赐予名为永恒的恩赐。就像每个圣徒一样，你的遗体不会损坏，你的尸骸将永不腐朽。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=t(o,[["render",d]]);export{b as __pageData,m as default};
